import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Numeric bounds derived from a [FractalParameter] schema.
///
/// Integer schemas store bounds as doubles because they share the numeric
/// parameter contract with float sliders. [containsInteger] exposes the hidden
/// assumption that those double bounds still include at least one valid integer
/// value before integer rounding is applied.
final class FractalNumericParamBounds {
  const FractalNumericParamBounds({
    required this.min,
    required this.max,
  });

  factory FractalNumericParamBounds.fromSchema(FractalParameter schema) {
    return FractalNumericParamBounds(min: schema.min, max: schema.max);
  }

  final double min;
  final double max;

  bool get containsInteger => min.ceil() <= max.floor();

  double normalizeFloat(double value) => value.clamp(min, max).toDouble();

  int normalizeInteger(double value) {
    assert(
      containsInteger,
      'integer parameter bounds must include at least one integer value',
    );
    final rounded = normalizeFloat(value).round();
    if (!containsInteger) return rounded;
    return rounded.clamp(min.ceil(), max.floor()).toInt();
  }
}

/// Normalizes raw parameter values against a module parameter schema.
///
/// This keeps replayed state, presets, and direct UI updates on the same
/// contract: finite numeric values clamp to schema bounds after type coercion,
/// enum values must be one of the declared options, booleans must be real
/// booleans, and non-finite numeric values fall back to the schema default
/// instead of being promoted to an arbitrary bound.
Object normalizeFractalParamValue(FractalParameter schema, Object value) {
  if (schema.type == FractalParamType.boolean) {
    return value is bool ? value : _booleanDefault(schema);
  }
  if (schema.type == FractalParamType.enumeration) {
    final optionValues = schema.options.map((option) => option.value).toSet();
    return optionValues.contains(value) ? value : schema.defaultValue;
  }

  final numericValue = _finiteNumericValue(value);
  if (numericValue != null) {
    final bounds = FractalNumericParamBounds.fromSchema(schema);
    if (schema.type == FractalParamType.integer) {
      return bounds.normalizeInteger(numericValue);
    }
    return bounds.normalizeFloat(numericValue);
  }
  return schema.defaultValue;
}

double? _finiteNumericValue(Object value) {
  if (value is! num) return null;
  final numericValue = value.toDouble();
  return numericValue.isFinite ? numericValue : null;
}

bool _booleanDefault(FractalParameter schema) {
  final defaultValue = schema.defaultValue;
  return defaultValue is bool ? defaultValue : false;
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Replayable decision for snapping a randomized float to slider precision.
///
/// Parameter schemas are hand-authored across a large catalog. A malformed
/// non-finite step or raw value must not crash randomization before the shared
/// schema normalizer gets a chance to clamp/fallback the value.
final class FractalParamStepSnapPlan {
  final double inputValue;
  final double step;
  final double value;
  final bool appliedStep;

  const FractalParamStepSnapPlan._({
    required this.inputValue,
    required this.step,
    required this.value,
    required this.appliedStep,
  });

  factory FractalParamStepSnapPlan.fromValue({
    required double value,
    required double step,
  }) {
    if (!value.isFinite || !step.isFinite || step <= 0.0) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    final snapped = (value / step).round() * step;
    if (!snapped.isFinite) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    return FractalParamStepSnapPlan._(
      inputValue: value,
      step: step,
      value: double.parse(snapped.toStringAsFixed(6)),
      appliedStep: true,
    );
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  return FractalParamStepSnapPlan.fromValue(value: value, step: step).value;
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _booleanParam({required bool defaultValue}) {
  return FractalParameter(
    id: 'enabled',
    label: _label,
    type: FractalParamType.boolean,
    min: 0,
    max: 1,
    step: 1,
    defaultValue: defaultValue,
  );
}

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

void main() {
  group('normalizeFractalParamValue', () {
    test('preserves real boolean parameter values', () {
      final schema = _booleanParam(defaultValue: true);

      expect(normalizeFractalParamValue(schema, true), isTrue);
      expect(normalizeFractalParamValue(schema, false), isFalse);
    });

    test('falls back to boolean schema default for non-boolean values', () {
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: true), 'true'),
        isTrue,
      );
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: false), 1),
        isFalse,
      );
    });

    test('falls back to numeric schema default for non-finite numbers', () {
      final floatSchema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );
      final intSchema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      for (final candidate in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        expect(
          normalizeFractalParamValue(floatSchema, candidate),
          4.0,
          reason: 'float candidate=$candidate',
        );
        expect(
          normalizeFractalParamValue(intSchema, candidate),
          4,
          reason: 'integer candidate=$candidate',
        );
      }
    });

    test('keeps rounded integer values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
        min: 1.2,
        max: 10.8,
      );
      final bounds = FractalNumericParamBounds.fromSchema(schema);

      expect(bounds.containsInteger, isTrue);
      expect(normalizeFractalParamValue(schema, 1.2), 2);
      expect(normalizeFractalParamValue(schema, 10.8), 10);
    });
  });
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_randomizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1.2,
  double max = 10.8,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

final class _FixedRandom implements Random {
  _FixedRandom({
    required this.nextIntValue,
    this.nextDoubleValue = 0.0,
  });

  final int Function(int max) nextIntValue;
  final double nextDoubleValue;

  @override
  int nextInt(int max) => nextIntValue(max);

  @override
  double nextDouble() => nextDoubleValue;

  @override
  bool nextBool() => false;
}

void main() {
  group('FractalParamStepSnapPlan', () {
    test('exposes whether slider-step snapping was applied', () {
      final snapped = FractalParamStepSnapPlan.fromValue(
        value: 1.234567,
        step: 0.1,
      );
      final unsnapped = FractalParamStepSnapPlan.fromValue(
        value: 1.234567,
        step: double.nan,
      );

      expect(snapped.value, 1.2);
      expect(snapped.appliedStep, isTrue);
      expect(unsnapped.value, 1.234567);
      expect(unsnapped.appliedStep, isFalse);
    });
  });

  group('roundFractalParamValueToStep', () {
    test('ignores non-finite steps instead of throwing during randomization',
        () {
      expect(roundFractalParamValueToStep(1.234567, double.nan), 1.234567);
      expect(roundFractalParamValueToStep(1.234567, double.infinity), 1.234567);
    });

    test('keeps non-finite values replayable for later schema normalization',
        () {
      expect(roundFractalParamValueToStep(double.nan, 0.1), isNaN);
      expect(
          roundFractalParamValueToStep(double.infinity, 0.1), double.infinity);
    });
  });

  group('randomFractalParamValue', () {
    test('keeps integer random values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(nextIntValue: (max) => max - 1),
        ),
        10,
      );
    });

    test('normalizes stepped float random values back to schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        1.2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(
            nextIntValue: (_) => 0,
            nextDoubleValue: 0.99,
          ),
        ),
        10.8,
      );
    });

    test('does not crash when a float schema has a non-finite step', () {
      final schema = FractalParameter(
        id: 'value',
        label: _label,
        type: FractalParamType.float,
        min: 1.2,
        max: 10.8,
        step: double.nan,
        defaultValue: 4.0,
      );

      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(
            nextIntValue: (_) => 0,
            nextDoubleValue: 0.5,
          ),
        ),
        closeTo(6.0, 1e-12),
      );
    });
  });
}

      'zoom': clampedZoom,
      if (autoIterations != null) 'autoIterations': autoIterations,
    });
  }

  /// Updates the 2D pan offset.
  ///
  /// Each component of [pan] is clamped to range [-3.0, 3.0].
  /// Used for 2D fractals to navigate the complex plane.
  void updatePan(Vector2 pan) {
    _view = _view.copyWith(
      pan: Vector2(
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.x,
          current: _view.pan.x,
        ),
        FractalViewInputBounds.normalizePanComponent(
          candidate: pan.y,
          current: _view.pan.y,
        ),
      ),
    );
    notifyListeners();
    _logChange('userAction', 'pan', 'Pan updated',
        metadata: {'x': pan.x, 'y': pan.y});
  }

  /// Updates the 3D rotation angles.
  ///
  /// Used for 3D fractals like Mandelbulb to control camera orientation.
  void updateRotation(Vector3 rotation) {
    _view = _view.copyWith(
      rotation: FractalViewInputBounds.normalizeRotation(
        candidate: rotation,
        current: _view.rotation,
      ),
    );
    notifyListeners();
  }

  /// Locks or unlocks gesture-based rotation.
  void setRotationLocked(bool value) {
    if (_rotationLocked == value) return;
    _rotationLocked = value;
    notifyListeners();
    _logChange(
      'stateChange',
      'rotationLock',
      value ? 'Rotation locked' : 'Rotation unlocked',
    );
  }

  /// Toggles gesture-based rotation lock.
  void toggleRotationLock() {
    setRotationLocked(!_rotationLocked);
  }

  void setGlowEnabled(bool value) {
    if (_glowEnabled == value) return;
    _glowEnabled = value;
    notifyListeners();
  }

  void setGlowSigma(double value) {
    _glowSigma = FractalEffectInputBounds.normalizeGlowSigma(
      candidate: value,
      current: _glowSigma,
    );
    notifyListeners();
  }

  void setGlowIntensity(double value) {
    _glowIntensity = FractalEffectInputBounds.normalizeGlowIntensity(
      candidate: value,
      current: _glowIntensity,
    );
    notifyListeners();
  }

  /// Sets whether the background should be transparent.
  ///
  /// When [value] is true, the shader renders background pixels
  /// with alpha=0, suitable for transparent PNG export.
  void setTransparentBackground(bool value) {
    _transparentBackground = value;
    notifyListeners();
  }

  void _logChange(String type, String category, String message,
      {Map<String, dynamic>? metadata}) {
    _logger?.log(LogEvent(
      timestamp: DateTime.now(),
      type: type,
      category: category,
      message: message,
      metadata: metadata,
    ));
  }

  /// Records finding an interesting spot in the fractal.
  ///
  /// When multiple interesting spots are found in quick succession,
  /// triggers a celebration effect.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _consecutiveInterestingSpots++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_consecutiveInterestingSpots >= 3) {
          celebrate();
          _consecutiveInterestingSpots = 0;
        }
      } else {
        _consecutiveInterestingSpots = 1;
      }
    } else {
      _consecutiveInterestingSpots = 1;
    }

    _lastInterestingSpotTime = now;
    _logChange('userAction', 'discovery', 'Found interesting spot');
  }

  /// Manually triggers a celebration effect.
  void celebrate() {
    if (_isCelebrating) return;

    _isCelebrating = true;
    if (!_isTest) {
      HapticFeedback.mediumImpact();
    }
    _celebrationController.add(null);
    notifyListeners();

    // Skip timer in test mode
    if (_isTest) {
      _isCelebrating = false;
      return;
    }

    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _isCelebrating = false;
      notifyListeners();
    });

    _logChange('event', 'celebration', 'Celebration triggered');
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();
    _celebrationController.close();
    super.dispose();
  }

  void _applyPreset(FractalPreset preset) {
    _params = _normalizedParamsForPreset(preset);
    _applyPresetView(preset.view);
  }

  Map<String, Object> _normalizedParamsForPreset(FractalPreset preset) {
    final defaults = <String, Object>{
      for (final param in _module.parameters) param.id: param.defaultValue,
    };

    final merged = {
      ...defaults,
      ...preset.params,
    };

    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      clamped[param.id] = normalizeFractalParamValue(
        param,
        merged[param.id] ?? param.defaultValue,
      );
    }
    return clamped;
  }

  void _applyPresetView(FractalViewState view) {
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;
  }

  int? _applyAdaptiveIterationsForZoom({
    required double zoom,
    required bool zoomingIn,
  }) {
    if (!_adaptiveIterationsEnabled || !zoomingIn) {
      return null;
    }
    if (_module.dimension != FractalDimension.twoD) {
      return null;
    }

    final iterationsSchema = _findParam('iterations');
    if (iterationsSchema == null ||
        iterationsSchema.type != FractalParamType.integer) {
      return null;
    }

    final minIterations = iterationsSchema.min.round();
    final maxIterations = iterationsSchema.max.round();
    final currentValue = _params['iterations'];
    final currentIterations = currentValue is num
        ? currentValue.round()
        : (iterationsSchema.defaultValue as num).round();
    final baseIterations = (iterationsSchema.defaultValue as num).round();

    final targetIterations = _suggestIterationsForZoom(
      zoom: zoom,
      baseIterations: baseIterations,
      minIterations: minIterations,
      maxIterations: maxIterations,
    );
    if (targetIterations <= currentIterations) {
      return null;
    }

    final delta = targetIterations - currentIterations;
    final step = delta >= 256
        ? 64
        : delta >= 96
            ? 32
            : delta >= 32
                ? 16
                : _adaptiveIterationsMinStep;
    final nextIterations =
        (currentIterations + step).clamp(minIterations, maxIterations);
    if (nextIterations <= currentIterations) {
      return null;
    }

    _params = Map<String, Object>.from(_params);
    _params['iterations'] = nextIterations;
    _logChange(
      'stateChange',
      'adaptiveIterations',
      'Adaptive iterations increased',
      metadata: {
        'module': _module.id,
        'zoom': zoom,
        'from': currentIterations,
        'to': nextIterations,
        'target': targetIterations,
      },
    );
    return nextIterations;
  }

  int _suggestIterationsForZoom({
    required double zoom,
    required int baseIterations,
    required int minIterations,
    required int maxIterations,
  }) {
    final safeZoom = max(1.0, zoom);
    final zoomOctaves = log(safeZoom) / ln2;
    final extra = max(0, (zoomOctaves * 48.0).round());
    final raw = baseIterations + extra;
    // Snap to a small step to avoid jittery one-by-one jumps.
    final snapped = ((raw + 3) ~/ 4) * 4;
    return snapped.clamp(minIterations, maxIterations);
  }

  FractalParameter? _findParam(String id) {
    for (final param in _module.parameters) {
      if (param.id == id) {
        return param;
      }
    }
    return null;
  }

  /// Alias for [view] for backward compatibility.
  FractalViewState get viewState => view;

  /// The currently selected fractal module (alias for [module]).
  FractalModule get currentModule => _module;

  /// Loads a complete state from another controller or snapshot.
  ///
  /// This initializes the controller from a full state including
  /// module, parameters, view state, and transparency setting.
  /// Parameters are clamped to the target module's schema.
  ///
  /// Can accept either a [module] object directly or a [moduleId] string.
  void loadState({
    FractalModule? module,
    String? moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
    bool transparentBackground = false,
    bool animateModule = false,
  }) {
    // Find the module by ID or use provided module
    final FractalModule targetModule;
    if (module != null) {
      targetModule = module;
    } else if (moduleId != null) {
      targetModule = registry.modules.firstWhere(
        (m) => m.id == moduleId,
        orElse: () => _module,
      );
    } else {
      targetModule = _module;
    }

    // Switch to the target module
    if (targetModule.id != _module.id) {
      if (animateModule) {
        selectModule(targetModule, animate: true);
      } else {
        _module = targetModule;
      }
    }

    _applyKaleidoscopeModulePolicy(_module.id);

    // Apply parameters with clamping
    final clamped = <String, Object>{};
    for (final param in _module.parameters) {
      final value = params[param.id] ?? param.defaultValue;
      clamped[param.id] = normalizeFractalParamValue(param, value);
    }
    _params = clamped;

    // Set view state
    _view = FractalViewInputBounds.normalizeView(
      candidate: view,
      current: _view,
      moduleId: _module.id,
    );
    _lastAdaptiveZoom = _view.zoom;

    // Set transparency
    _transparentBackground = transparentBackground;

    notifyListeners();
    _logChange('stateChange', 'loadState', 'Loaded state for ${_module.id}');
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized string for the current locale.
///
/// Used for parameter labels and option descriptions.
typedef LocalizedText = String Function(AppLocalizations l10n);

/// The data type of a fractal parameter.
///
/// Determines how the parameter is rendered in the UI and how its
/// value is validated and stored.
enum FractalParamType {
  /// A floating-point number parameter.
  ///
  /// Rendered as a slider with continuous values.
  /// Value type: [double]
  float,

  /// An integer parameter.
  ///
  /// Rendered as a slider with discrete steps.
  /// Value type: [int]
  integer,

  /// A selection from a fixed set of options.
  ///
  /// Rendered as a dropdown or segmented control.
  /// Value type: depends on [FractalParamOption.value]
  enumeration,

  /// A boolean on/off parameter.
  ///
  /// Rendered as a switch or checkbox.
  /// Value type: [bool]
  boolean,
}

/// An option for an enumeration-type parameter.
///
/// Defines a single selectable value with its display label.
///
/// Example:
/// ```dart
/// FractalParamOption(
///   value: 0,
///   label: (l10n) => l10n.colorFire,
/// )
/// ```
class FractalParamOption {
  /// The underlying value for this option.
  ///
  /// This is what gets stored in the parameter map and passed to shaders.
  final Object value;

  /// Returns the localized display label for this option.
  final LocalizedText label;

  /// Creates a new parameter option.
  const FractalParamOption({
    required this.value,
    required this.label,
  });
}

/// Defines the schema for a configurable fractal parameter.
///
/// A [FractalParameter] describes how a single adjustable value should
/// behave: its valid range, step increment, default value, and UI
/// representation.
///
/// Parameters are defined per [FractalModule] and used to:
/// - Generate the controls UI automatically
/// - Validate user input
/// - Clamp values to valid ranges
/// - Store and restore presets
///
/// {@category Models}
///
/// Example:
/// ```dart
/// FractalParameter(
///   id: 'iterations',
///   label: (l10n) => l10n.paramIterations,
///   type: FractalParamType.integer,
///   min: 10,
///   max: 500,
///   step: 1,
///   defaultValue: 100,
/// )
/// ```
@immutable
class FractalParameter {
  /// Unique identifier for this parameter.
  ///
  /// Used as the key in parameter maps and for preset serialization.
  /// Should be a lowercase, camelCase string (e.g., 'iterations', 'colorScheme').
  final String id;

  /// Returns the localized display label for this parameter.
  ///
  /// Shown in the controls UI next to the input widget.
  final LocalizedText label;

  /// The data type of this parameter.
  ///
  /// Determines the UI widget and value handling.
  final FractalParamType type;

  /// The minimum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration] and [FractalParamType.boolean],
  /// this is typically 0.
  final double min;

  /// The maximum allowed value (for numeric types).
  ///
  /// For [FractalParamType.enumeration], this should match `options.length - 1`.
  final double max;

  /// The step increment for slider-based inputs.
  ///
  /// For integers, use 1.0. For floats, use an appropriate precision
  /// (e.g., 0.1 or 0.01).
  final double step;

  /// The initial value when no preset is applied.
  ///
  /// Must be within the [min]/[max] range and compatible with [type].
  final Object defaultValue;

  /// Available options for enumeration-type parameters.
  ///
  /// Only used when [type] is [FractalParamType.enumeration].
  /// Empty for other types.
  final List<FractalParamOption> options;

  /// Creates a new [FractalParameter] with the specified schema.
  ///
  /// For enumeration types, ensure [options] is populated with
  /// all valid choices.
  const FractalParameter({
    required this.id,
    required this.label,
    required this.type,
    required this.min,
    required this.max,
    required this.step,
    required this.defaultValue,
    this.options = const [],
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

FractalViewState _snapshotPresetView(FractalViewState view) {
  return FractalViewState(
    pan: view.pan,
    zoom: view.zoom,
    rotation: view.rotation,
  );
}

Map<String, Object> _snapshotPresetParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: _snapshotPresetParamValue(entry.value),
  });
}

Object _snapshotPresetParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? _snapshotPresetParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? _snapshotPresetParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  ///
  /// The supplied view vectors and parameter collections are snapshotted so a
  /// preset remains replayable even when callers mutate their originals.
  FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required Map<String, Object> params,
    required FractalViewState view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  })  : params = _snapshotPresetParams(params),
        view = _snapshotPresetView(view);

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map)
          .map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('FractalController state exposure', () {
    test('exposes params as a read-only snapshot', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      final initialIterations = controller.params['iterations'];
      final exposedParams = controller.params;

      expect(
        () => exposedParams['iterations'] = double.nan,
        throwsUnsupportedError,
      );
      expect(controller.params['iterations'], initialIterations);
    });

    test('exposes view vectors as snapshots instead of mutable state', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.updatePan(Vector2(0.25, -0.5));
      controller.updateRotation(Vector3(0.1, 0.2, 0.3));

      final exposedView = controller.view;
      exposedView.pan.setValues(2.0, 3.0);
      exposedView.rotation.setValues(4.0, 5.0, 6.0);

      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));

      final exposedAlias = controller.viewState;
      exposedAlias.pan.setValues(-2.0, -3.0);
      exposedAlias.rotation.setValues(-4.0, -5.0, -6.0);

      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FractalController effect input bounds', () {
    test('preserves glow settings when replayed values are NaN', () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.setGlowSigma(2.5);
      controller.setGlowIntensity(0.6);

      controller.setGlowSigma(double.nan);
      controller.setGlowIntensity(double.nan);

      expect(controller.glowSigma, 2.5);
      expect(controller.glowIntensity, 0.6);
    });

    test('preserves kaleidoscope rotation when replayed values are non-finite',
        () {
      final controller = FractalController(ModuleRegistry());
      addTearDown(controller.dispose);

      controller.setKaleidoscopeRotation(0.75);

      controller.setKaleidoscopeRotation(double.nan);
      expect(controller.kaleidoscopeRotation, 0.75);

      controller.setKaleidoscopeRotation(double.infinity);
      expect(controller.kaleidoscopeRotation, 0.75);
    });

    test('does not leak forced kaleidoscope defaults after module exit', () {
      final registry = ModuleRegistry();
      final controller = FractalController(registry);
      addTearDown(controller.dispose);

      final normalModule = registry.byId('mandelbrot');
      final kaleidoscopeModule = registry.byId('kaleidoscope_basic');

      controller.selectModule(normalModule, animate: false);
      controller.setKaleidoscopeEnabled(false);
      controller.setKaleidoscopeSectors(6);
      controller.setKaleidoscopeMirrorMode(1);

      controller.selectModule(kaleidoscopeModule, animate: false);

      expect(controller.kaleidoscopeEnabled, isTrue);
      expect(controller.kaleidoscopeSectors, 16);
      expect(controller.kaleidoscopeMirrorMode, 3);

      controller.selectModule(normalModule, animate: false);

      expect(controller.kaleidoscopeEnabled, isFalse);
      expect(controller.kaleidoscopeSectors, 6);
      expect(controller.kaleidoscopeMirrorMode, 1);
    });
  });
}

