python3 - <<'PY'
import re, pathlib, math
root=pathlib.Path('lib')
# naive find FractalParameter blocks containing type: FractalParamType.integer
bad=[]
for p in root.rglob('*.dart'):
    s=p.read_text()
    for m in re.finditer(r'FractalParameter\s*\((.*?)\n\s*\)', s, re.S):
        block=m.group(1)
        if 'FractalParamType.integer' not in block: continue
        def val(name):
            mm=re.search(rf'{name}:\s*([^,\n]+)', block)
            if not mm: return None
            t=mm.group(1).strip()
            try:
                return float(eval(t, {"__builtins__":{}}, {}))
            except Exception:
                return t
        mn=val('min'); mx=val('max')
        if isinstance(mn,float) and isinstance(mx,float):
            if math.ceil(mn)>math.floor(mx):
                bad.append((str(p), mn, mx, block[:200].replace('\n',' ')))
print('bad integer ranges', len(bad))
for row in bad[:20]: print(row)
PY

